def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Resolve any options whose default is a dynamic default
    mapping, now that every parameter has been parsed. Only
    parameters that were not given a value from another source
    (i.e. their source is still :attr:`ParameterSource.DEFAULT`)
    are affected.
    """
    params = self.get_params(ctx)
    opt_to_param = {
        opt: param
        for param in params
        for opt in (*param.opts, *getattr(param, "secondary_opts", ()))
    }

    for param in params:
        dynamic_default = getattr(param, "_dynamic_default", None)

        if dynamic_default is None:
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

